import{_ as o,o as t,c as a,ag as i}from"./chunks/framework.CHQlKclR.js";const p=JSON.parse('{"title":"Math & Utilities","description":"","frontmatter":{},"headers":[],"relativePath":"api/utilities.md","filePath":"api/utilities.md"}'),r={name:"api/utilities.md"};function d(n,e,s,l,c,u){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="math-utilities" tabindex="-1">Math &amp; Utilities <a class="header-anchor" href="#math-utilities" aria-label="Permalink to &quot;Math &amp; Utilities&quot;">​</a></h1><p>The <code>vortex::util</code> namespace contains highly optimized math functions and coordinate structures used throughout the library.</p><h2 id="common-enums" tabindex="-1">Common Enums <a class="header-anchor" href="#common-enums" aria-label="Permalink to &quot;Common Enums&quot;">​</a></h2><p>Vortex uses specific enumerations to standardize movement behavior and system states.</p><h3 id="e-angle-behavior" tabindex="-1"><code>e_angle_behavior</code> <a class="header-anchor" href="#e-angle-behavior" aria-label="Permalink to &quot;`e_angle_behavior`&quot;">​</a></h3><p>Defines how the robot calculates its turn direction.</p><ul><li><code>vortex::shortest</code>: Turns the fewest degrees to reach the target.</li><li><code>vortex::longest</code>: Turns the long way around.</li><li><code>vortex::left_turn</code>: Forces a counter-clockwise turn.</li><li><code>vortex::right_turn</code>: Forces a clockwise turn.</li><li><code>vortex::raw</code>: No normalization (uses raw gyro values).</li></ul><h3 id="drive-directions" tabindex="-1"><code>drive_directions</code> <a class="header-anchor" href="#drive-directions" aria-label="Permalink to &quot;`drive_directions`&quot;">​</a></h3><p>Specifies the forward face of the robot for a motion.</p><ul><li><code>vortex::fwd</code> / <code>vortex::forward</code>: Movement uses the front of the robot.</li><li><code>vortex::rev</code> / <code>vortex::reverse</code>: Movement uses the back of the robot.</li></ul><h3 id="exit-output" tabindex="-1"><code>exit_output</code> <a class="header-anchor" href="#exit-output" aria-label="Permalink to &quot;`exit_output`&quot;">​</a></h3><p>Returned by PID controllers to indicate why a motion stopped.</p><ul><li><code>vortex::RUNNING</code>: Motion is still active.</li><li><code>vortex::SMALL_EXIT</code>: Settled within the small error threshold.</li><li><code>vortex::BIG_EXIT</code>: Settled within the big error threshold (failsafe).</li><li><code>vortex::VELOCITY_EXIT</code>: Robot has stopped moving/stalled.</li><li><code>vortex::mA_EXIT</code>: Motors exceeded current limit.</li></ul><h3 id="e-swing" tabindex="-1"><code>e_swing</code> <a class="header-anchor" href="#e-swing" aria-label="Permalink to &quot;`e_swing`&quot;">​</a></h3><p>Used in swing PID motions to specify the pivot side.</p><ul><li><code>vortex::LEFT_SWING</code>: Left side motors are stopped/slowed, right side pivots.</li><li><code>vortex::RIGHT_SWING</code>: Right side motors are stopped/slowed, left side pivots.</li></ul><hr><h2 id="coordinate-structures" tabindex="-1">Coordinate Structures <a class="header-anchor" href="#coordinate-structures" aria-label="Permalink to &quot;Coordinate Structures&quot;">​</a></h2><h3 id="pose" tabindex="-1"><code>pose</code> <a class="header-anchor" href="#pose" aria-label="Permalink to &quot;`pose`&quot;">​</a></h3><p>A simple structure representing a 2D position and heading.</p><ul><li><strong>double x</strong>: X-coordinate (inches).</li><li><strong>double y</strong>: Y-coordinate (inches).</li><li><strong>double theta</strong>: Heading (degrees).</li></ul><h3 id="united-pose" tabindex="-1"><code>united_pose</code> <a class="header-anchor" href="#united-pose" aria-label="Permalink to &quot;`united_pose`&quot;">​</a></h3><p>Similar to <code>pose</code>, but uses <strong>OkapiLib units</strong> for type-safety.</p><ul><li><strong>okapi::QLength x</strong></li><li><strong>okapi::QLength y</strong></li><li><strong>okapi::QAngle theta</strong></li></ul><h3 id="odom-united-odom" tabindex="-1"><code>odom</code> / <code>united_odom</code> <a class="header-anchor" href="#odom-united-odom" aria-label="Permalink to &quot;`odom` / `united_odom`&quot;">​</a></h3><p>Used to define a complete movement target for odometry functions.</p><ul><li><code>pose target</code>: The {x, y, theta} to reach.</li><li><code>drive_directions drive_direction</code>: <code>fwd</code> or <code>rev</code>.</li><li><code>int max_xy_speed</code>: Speed cap for the motion (1-127).</li><li><code>e_angle_behavior turn_behavior</code>: Default is <code>shortest</code>.</li></ul><hr><h2 id="math-helpers" tabindex="-1">Math Helpers <a class="header-anchor" href="#math-helpers" aria-label="Permalink to &quot;Math Helpers&quot;">​</a></h2><h3 id="double-wrap-angle-double-theta" tabindex="-1"><code>double wrap_angle(double theta)</code> <a class="header-anchor" href="#double-wrap-angle-double-theta" aria-label="Permalink to &quot;`double wrap_angle(double theta)`&quot;">​</a></h3><p>Constrains an angle between <strong>-180 and 180 degrees</strong>.</p><h3 id="int-sgn-double-input" tabindex="-1"><code>int sgn(double input)</code> <a class="header-anchor" href="#int-sgn-double-input" aria-label="Permalink to &quot;`int sgn(double input)`&quot;">​</a></h3><p>Returns <code>1</code> if positive, <code>-1</code> if negative, and <code>0</code> if zero.</p><h3 id="double-clamp-double-input-double-max-double-min" tabindex="-1"><code>double clamp(double input, double max, double min)</code> <a class="header-anchor" href="#double-clamp-double-input-double-max-double-min" aria-label="Permalink to &quot;`double clamp(double input, double max, double min)`&quot;">​</a></h3><p>Restricts <code>input</code> to be between <code>min</code> and <code>max</code>.</p><h3 id="double-to-rad-double-deg-double-to-deg-double-rad" tabindex="-1"><code>double to_rad(double deg)</code> / <code>double to_deg(double rad)</code> <a class="header-anchor" href="#double-to-rad-double-deg-double-to-deg-double-rad" aria-label="Permalink to &quot;`double to_rad(double deg)` / `double to_deg(double rad)`&quot;">​</a></h3><p>Standard trigonometric conversions.</p><h2 id="geometric-functions" tabindex="-1">Geometric Functions <a class="header-anchor" href="#geometric-functions" aria-label="Permalink to &quot;Geometric Functions&quot;">​</a></h2><h3 id="double-absolute-angle-to-point-pose-target-pose-current" tabindex="-1"><code>double absolute_angle_to_point(pose target, pose current)</code> <a class="header-anchor" href="#double-absolute-angle-to-point-pose-target-pose-current" aria-label="Permalink to &quot;`double absolute_angle_to_point(pose target, pose current)`&quot;">​</a></h3><p>Returns the absolute heading required to face a target point.</p><h3 id="double-distance-to-point-pose-target-pose-current" tabindex="-1"><code>double distance_to_point(pose target, pose current)</code> <a class="header-anchor" href="#double-distance-to-point-pose-target-pose-current" aria-label="Permalink to &quot;`double distance_to_point(pose target, pose current)`&quot;">​</a></h3><p>Returns the Euclidean distance (inches) between two points.</p><h3 id="pose-vector-off-point-double-distance-pose-current" tabindex="-1"><code>pose vector_off_point(double distance, pose current)</code> <a class="header-anchor" href="#pose-vector-off-point-double-distance-pose-current" aria-label="Permalink to &quot;`pose vector_off_point(double distance, pose current)`&quot;">​</a></h3><p>Returns a new <code>pose</code> projected <code>distance</code> inches away from the <code>current</code> pose.</p><h2 id="text-screen" tabindex="-1">Text &amp; Screen <a class="header-anchor" href="#text-screen" aria-label="Permalink to &quot;Text &amp; Screen&quot;">​</a></h2><h3 id="void-screen-print-std-string-text-int-line-0" tabindex="-1"><code>void screen_print(std::string text, int line = 0)</code> <a class="header-anchor" href="#void-screen-print-std-string-text-int-line-0" aria-label="Permalink to &quot;`void screen_print(std::string text, int line = 0)`&quot;">​</a></h3><p>Prints to the brain screen. Handles <code>\\n</code> and line wraps at 32 characters.</p><h3 id="void-vortex-print" tabindex="-1"><code>void vortex_print()</code> <a class="header-anchor" href="#void-vortex-print" aria-label="Permalink to &quot;`void vortex_print()`&quot;">​</a></h3><p>Prints the Vortex ASCII logo and version info to the terminal.</p><h3 id="std-string-exit-to-string-exit-output-input" tabindex="-1"><code>std::string exit_to_string(exit_output input)</code> <a class="header-anchor" href="#std-string-exit-to-string-exit-output-input" aria-label="Permalink to &quot;`std::string exit_to_string(exit_output input)`&quot;">​</a></h3><p>Converts an <code>exit_output</code> enum into a human-readable string for logging.</p>',51)])])}const b=o(r,[["render",d]]);export{p as __pageData,b as default};
